sql:
SELECT contribution_date, contribution_type, data_quality
FROM data_contributions
ORDER BY contribution_date DESC;

external_knowledge:
- 'most frequently contributed' refers to the highest count of contribution_id for each parameter_name; 
- 'during 2023' refers to the period between January 1st, 2023, and December 31st, 2023; 
- 'exceeds a dozen' means having more than 10 contribution_id for each parameter_name.

sql:
SELECT DISTINCT i.institution_name
FROM data_contributions dc
INNER JOIN research_institutions i ON dc.institution_id = i.institution_id;

SELECT COUNT(*) AS institution_count
FROM research_institutions
WHERE email LIKE '%@institution2.com';

SELECT COUNT(*) AS number_of_contributions
FROM data_contributions
WHERE parameter_id = (SELECT parameter_id FROM parameters WHERE parameter_name = 'T2M');

SELECT station_name, installation_date
FROM measurement_stations
WHERE status = 'active';

SELECT institution_id, COUNT(contribution_id) AS number_of_contributions
FROM data_contributions
GROUP BY institution_id;

SELECT institution_name, email
FROM research_institutions
WHERE institution_id = 1;

SELECT contribution_date, contribution_type
FROM data_contributions
ORDER BY contribution_date ASC;
